1	export type SpeedKey = readonly [time: number, factor: number];
2	
3	export type SpeedProfileOptions = {
4	  samples?: number;
5	};
6	
7	export function createSpeedProfile(keys: readonly SpeedKey[], duration: number, options: SpeedProfileOptions = {}) {
8	  if (keys.length === 0) throw new Error('createSpeedProfile requires at least one speed key');
9	  const samples = options.samples ?? 1200;
10	  if (!Number.isFinite(samples) || samples <= 0) throw new Error('createSpeedProfile samples must be positive');
11	
12	  function speedAt(time: number) {
13	    const t = clamp(time, 0, duration);
14	    for (let i = 1; i < keys.length; i += 1) {
15	      if (t <= keys[i][0]) {
16	        const [t0, v0] = keys[i - 1];
17	        const [t1, v1] = keys[i];
18	        return lerp(v0, v1, (t - t0) / Math.max(0.0001, t1 - t0));
19	      }
20	    }
21	    return keys[keys.length - 1][1];
22	  }
23	
24	  const table = [0];
25	  let sum = 0;
26	  const dt = duration / samples;
27	  for (let i = 1; i <= samples; i += 1) {
28	    const mid = (i - 0.5) * dt;
29	    sum += speedAt(mid) * dt;
30	    table.push(sum);
31	  }
32	  const total = table[samples];
33	  const easeTable = table.map((value) => value / total);
34	
35	  function runProgress(time: number, runDuration = duration) {
36	    const t = clamp(time / runDuration, 0, 1) * samples;
37	    const index = Math.min(samples - 1, Math.floor(t));
38	    return lerp(easeTable[index], easeTable[index + 1], t - index);
39	  }
40	
41	  return { speedAt, runProgress };
42	}
43	
44	function clamp(value: number, min: number, max: number) {
45	  return Math.min(max, Math.max(min, value));
46	}
47	
48	function lerp(a: number, b: number, t: number) {
49	  return a + (b - a) * t;
50	}
