11	/** Advance a homing shot one step: speed ramps with age, velocity turns toward the target, position integrates. */
12	export function steerHomingShot(
13	  position: Vector3,
14	  velocity: Vector3,
15	  target: Vector3,
16	  age: number,
17	  dt: number,
18	  params: HomingSteerParams,
19	): void {
20	  const speed = Math.min(params.maxSpeed, params.baseSpeed + age * params.accel);
21	  const desired = target.clone().sub(position).normalize().multiplyScalar(speed);
22	  velocity.lerp(desired, Math.min(1, dt * params.turnRate));
23	  position.addScaledVector(velocity, dt);
24	}
