1	export type MusicTimeOptions = {
2	  /** Beats in one bar. Defaults to 4 for common-time levels. */
3	  beatsPerBar?: number;
4	  /** Authoring grid density for helpers that address steps. Defaults to 16. */
5	  stepsPerBar?: number;
6	};
7	
8	export type MusicMarkerInput = number | readonly [bar: number, beat: number];
9	
10	export type MusicTime = ReturnType<typeof createMusicTime>;
11	
12	/**
13	 * Converts musical positions into the seconds consumed by gameplay systems.
14	 * Bars are zero-based arrangement bars; beats are continuous and may be fractional.
15	 */
16	export function createMusicTime(bpm: number, options: MusicTimeOptions = {}) {
17	  const beatsPerBar = options.beatsPerBar ?? 4;
18	  const stepsPerBar = options.stepsPerBar ?? 16;
19	  const beatSeconds = 60 / bpm;
20	  const barSeconds = beatSeconds * beatsPerBar;
21	  const stepSeconds = barSeconds / stepsPerBar;
22	
23	  function beats(count: number) {
24	    return count * beatSeconds;
25	  }
26	
27	  function bar(index: number, beat = 0) {
28	    return (index * beatsPerBar + beat) * beatSeconds;
29	  }
30	
31	  function step(barIndex: number, stepInBar = 0) {
32	    return barIndex * barSeconds + stepInBar * stepSeconds;
33	  }
34	
35	  function seconds(value: number) {
36	    return value;
37	  }
38	
39	  function markers<const T extends Record<string, MusicMarkerInput>>(values: T): { [K in keyof T]: number } {
40	    const result = {} as { [K in keyof T]: number };
41	    for (const key of Object.keys(values) as Array<keyof T>) {
42	      const value = values[key] as MusicMarkerInput;
43	      result[key] = typeof value === 'number' ? bar(value) : bar(value[0], value[1]);
44	    }
45	    return result;
46	  }
47	
48	  return {
49	    bpm,
50	    beatsPerBar,
51	    stepsPerBar,
52	    beatSeconds,
53	    barSeconds,
54	    stepSeconds,
55	    beats,
56	    bar,
57	    step,
58	    seconds,
59	    markers,
60	  };
61	}
